// // This module calculates the two's complement of a 4-bit input value by inverting all bits and subtracting one from the least significant bit.
module top_module(
    input [3:0] in,
    output [3:0] out
);wire [3:0] neg_in;

    assign neg_in = ~in + 1'b1;
    assign out = neg_in;

endmodule
